import os
from dotenv import load_dotenv
from langchain_groq import ChatGroq
from langchain_google_genai import ChatGoogleGenerativeAI
from langchain_cohere import CohereEmbeddings

load_dotenv()

class ModelFactory:

    GROQ_MODEL = "llama-3.1-8b-instant"
    GEMINI_MODEL = "gemini-3.1-flash-lite"
    EMBEDDING_MODEL = "embed-v4.0"
    RERANK_MODEL = "rerank-v3.5"

    @classmethod
    def classifier(cls):
        return ChatGroq(
            model=cls.GROQ_MODEL,
            api_key=os.getenv("GROQ_API_KEY"), 
            temperature=0,
        )

    @classmethod
    def query_generator(cls):
        return ChatGroq(
            model=cls.GROQ_MODEL,
            api_key=os.getenv("GROQ_API_KEY"),
            temperature=0.2,
        )

    @classmethod
    def answer(cls):
        return ChatGoogleGenerativeAI(
            model=cls.GEMINI_MODEL,
            google_api_key=os.getenv("GOOGLE_API_KEY"),
            temperature=0.2,
        )

    @classmethod
    def embedding(cls):
        return CohereEmbeddings(  # pyright: ignore[reportCallIssue]
            model=cls.EMBEDDING_MODEL,
            cohere_api_key=os.getenv("COHERE_API_KEY"),
        )

    @classmethod
    def reranker_model(cls):
        return cls.RERANK_MODEL

from langchain_core.prompts import ChatPromptTemplate
from rag.model_factory import ModelFactory

class MultiQueryGenerator:

    def __init__(self):
        self.model = ModelFactory.query_generator()

        self.prompt = ChatPromptTemplate.from_template(
            """
Generate exactly 2 alternative search queries for the following repository question.

Original Query:
{original_query}

Instructions:
- Preserve the original meaning.
- Rephrase the query from different perspectives.
- Optimize the queries for retrieving relevant code, documentation, and implementation details.
- Return exactly 2 queries.
- Do not number the queries.
- Do not include explanations.
- Output only the queries, one per line.
"""
        )

    def generate(self, original_query: str):

        chain = self.prompt | self.model

        result = chain.invoke(
            {
                "original_query": original_query
            }
        )

        content = result.content

        if isinstance(content, list):
            text = "".join(
                item.get("text", "")
                for item in content
                if isinstance(item, dict)
            )
        else:
            text = str(content)

        generated_queries = [
            query.strip()
            for query in text.splitlines()
            if query.strip()
        ][:2]

        queries = [original_query] + generated_queries

        return list(dict.fromkeys(queries))

from rag.vector_store import VectorStore


class Retriever:

    def __init__(self, repository_name):
        self.vector_store = VectorStore(repository_name)

    def retrieve(self, queries, k=20):

        ranked_lists = []

        for query in queries:

            docs = self.vector_store.db.max_marginal_relevance_search(
                query=query,
                k=k,
                fetch_k=50,
                lambda_mult=0.5,
            )

            ranked_lists.append(docs)

        return ranked_lists

from collections import defaultdict


class ReciprocalRankFusion:

    def __init__(self, k: int = 60):
        self.k = k

    def fuse(self, ranked_lists):
        """
        ranked_lists: List[List[Document]]
        """

        scores = defaultdict(float)
        documents = {}

        for docs in ranked_lists:
            for rank, doc in enumerate(docs, start=1):

                key = doc.page_content

                documents[key] = doc
                scores[key] += 1 / (self.k + rank)

        ranked = sorted(
            scores.items(),
            key=lambda x: x[1],
            reverse=True,
        )

        return [documents[key] for key, _ in ranked]

from langchain_chroma import Chroma

from rag.embedding import EmbeddingModel


class VectorStore:

    def __init__(
        self,
        repository_name: str,
        persist_directory: str = "chroma_db",
    ):

        self.embedding = EmbeddingModel().get_embedding_model()

        self.collection_name = (
            repository_name.lower()
            .replace("/", "_")
            .replace("-", "_")
            .replace(" ", "_")
        )

        self.db = Chroma(
            collection_name=self.collection_name,
            persist_directory=persist_directory,
            embedding_function=self.embedding,
        )

    def clear(self):
        """
        Remove every document from this repository collection.
        """

        try:
            ids = self.db.get()["ids"]

            if ids:
                self.db.delete(ids=ids)

        except Exception:
            pass

    def add_documents(self, documents):
        self.db.add_documents(documents)

    def similarity_search(
        self,
        query: str,
        k: int = 5,
    ):
        return self.db.similarity_search(
            query=query,
            k=k,
        )

    def get_vector_store(self):
        return self.db

import json
import os


def build_structure(tree_items):
    structure = {}

    for item in tree_items:
        current = structure
        parts = item["path"].split("/")

        for i, part in enumerate(parts):
            is_last = i == len(parts) - 1

            if is_last:
                current.setdefault(part, {
                    "type": "directory" if item["type"] == "tree" else "file"
                })

                if item["type"] == "tree":
                    current[part].setdefault("children", {})

            else:
                node = current.setdefault(part, {
                    "type": "directory",
                    "children": {}
                })

                current = node["children"]

    return structure


def save_json(data, filename):
    """
    Save data as a JSON file.
    """

    # Automatically add the nested structure
    if "tree" in data:
        data["structure"] = build_structure(data["tree"])

    directory = os.path.dirname(filename)

    if directory:
        os.makedirs(directory, exist_ok=True)

    with open(filename, "w", encoding="utf-8", newline="\n") as f:
        json.dump(
            data,
            f,
            indent=4,
            ensure_ascii=False,
            sort_keys=False,
        )
        f.write("\n")

    print(f"Saved: {os.path.abspath(filename)}")
